<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    pushw %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ds</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">                            // save </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">DS</span></span>
